const cfg = $('⚙️ Load Config').item.json;
const raw = cfg.VIDEO_PRODUCTION_ENABLED;
const enabled = raw === true || String(raw).toLowerCase() === 'true';
return [{ json: { VIDEO_PRODUCTION_ENABLED: enabled, config: cfg } }];

const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'date';
const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'status') || 'status';
const urlKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('url') || k === 'WP URL') || 'wp_url';
const valid = rows.filter(r => {
  const d = (r[dateKey] || r.date || '').toString().slice(0, 10);
  const s = (r[statusKey] || r.status || '').toLowerCase();
  return d === today && s !== 'publish_failed';
});
if (valid.length === 0) return [{ json: { noPostToday: true } }];
const latest = valid[valid.length - 1];
const wpUrl = latest[urlKey] || latest.wp_url || '';
const slug = wpUrl.split('/').filter(Boolean).pop() || '';
return [{ json: { ...latest, slug, noPostToday: false } }];

const post = $input.first().json[0] || $input.first().json;
const filterRow = $('Filter today\'s post').item.json;
const title = post?.title?.rendered || filterRow.title || '';
const content = (post?.content?.rendered || '').replace(/<[^>]*>/g, '\n').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
const summary = content.slice(0, 3000);
return [{ json: { title, summary, wp_url: filterRow.wp_url || filterRow['WP URL'] || '', keyword: filterRow.keyword || title, slug: filterRow.slug } }];

const d = $input.first().json;
const schema = '{"success": true, "data": { "scripts": [ { "platform": "tiktok", "script": "...", "title": "..." }, { "platform": "yt_short", "script": "...", "title": "..." } ] }, "error": null }';
const prompt = 'Return only valid JSON. No text. No markdown. No explanations.
Schema: ' + schema + '

From this blog post, generate short video scripts for TikTok and YouTube Shorts (and optionally ig_reel). Use the title and summary below. Each script 30-60 seconds when read aloud, hook in first line, CTA to blog.

Title: ' + (d.title || '') + '

Summary: ' + (d.summary || '').slice(0, 3000) + '

Return the JSON object with success, data.scripts array, and error null.';
return [{ json: { ...d, prompt } }];

const raw = $input.first().json.response || '';
const prep = $('Prepare for LLM').item.json;
let parsed;
try {
  const str = (typeof raw === 'string' ? raw : '').replace(/\\n/g, '\n');
  const match = str.match(/```json\n([\s\S]*?)\n```/) || str.match(/(\{[\s\S]*\})/);
  const jsonStr = match ? (match[1] || match[0] || '{}').trim() : str;
  parsed = JSON.parse(jsonStr);
} catch(e) {
  parsed = { success: false, data: null, error: { code: 'parse_error', message: e.message } };
}
const scripts = (parsed.success && parsed.data && Array.isArray(parsed.data.scripts) && parsed.data.scripts.length > 0)
  ? parsed.data.scripts
  : [{ platform: 'tiktok', script: 'Check out our full guide at the link in bio!', title: prep.title }];
return [{ json: { success: parsed.success, data: { scripts }, error: parsed.error || null, wp_url: prep.wp_url, keyword: prep.keyword, title: prep.title } }];

const input = $input.first().json;
const scripts = input.data?.scripts || [];
const wpUrl = input.wp_url || '';
const keyword = input.keyword || '';
const postTitle = input.title || '';
return scripts.map(s => ({
  json: {
    script: s.script || '',
    title: s.title || postTitle,
    platform: (s.platform || 'tiktok').toLowerCase().replace(/\s/g, '_'),
    blog_url: wpUrl,
    keyword
  }
}));
